import java.util.*;

class Stop {
    int id;
    int distance;
    int credits;

    Stop(int id, int distance, int credits) {
        this.id = id;
        this.distance = distance;
        this.credits = credits;
    }
}

public class UberHCV {

    public static int findMinimumDistance(int N, int[] C, int M, int[][] roads, int S, int D) {
        List<List<int[]>> graph = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            graph.add(new ArrayList<>());
        }

        for (int[] road : roads) {
            graph.get(road[0]).add(new int[]{road[1], road[2]});
            graph.get(road[1]).add(new int[]{road[0], road[2]});
        }

        PriorityQueue<Stop> queue = new PriorityQueue<>(Comparator.comparingInt(s -> s.distance));
        queue.add(new Stop(S, 0, C[S]));

        int[][] minDistances = new int[N][101]; // Considering max credits as 100
        for (int[] row : minDistances) {
            Arrays.fill(row, Integer.MAX_VALUE);
        }
        minDistances[S][C[S]] = 0;

        while (!queue.isEmpty()) {
            Stop current = queue.poll();

            if (current.id == D) {
                return current.distance;
            }

            for (int[] neighbor : graph.get(current.id)) {
                int nextStop = neighbor[0];
                int roadLength = neighbor[1];
                int nextCredits = current.credits + C[nextStop] - roadLength;

                if (nextCredits >= 0 && nextCredits <= 100 && minDistances[nextStop][nextCredits] > current.distance + roadLength) {
                    minDistances[nextStop][nextCredits] = current.distance + roadLength;
                    queue.add(new Stop(nextStop, minDistances[nextStop][nextCredits], nextCredits));
                }
            }
        }

        return -1;
    }

    public static void main(String[] args) {
        int N = 5;
        int[] C = {2, 10, 5, 100, 3};
        int M = 8;
        int[][] roads = {
            {0, 1, 2},
            {0, 3, 5},
            {0, 2, 1},
            {1, 3, 10},
            {1, 4, 15},
            {2, 3, 7},
            {2, 4, 90},
            {3, 4, 80}
        };
        int S = 0;
        int D = 4;

        System.out.println("Minimum Distance: " + findMinimumDistance(N, C, M, roads, S, D));
    }
}

